455→    use crate::protocol::{DependencyKind, ExternalDependency};
456→
457→    fn make_analysis(
458→        name: &str,
459→        start_line: u32,
460→        end_line: u32,
461→        deps: Vec<&str>,
462→    ) -> FunctionAnalysis {
463→        FunctionAnalysis {
464→            name: name.to_string(),
465→            exported: true,
466→            params: vec![],
467→            branches: vec![],
468→            dependencies: deps
469→                .into_iter()
470→                .map(|s| ExternalDependency {
471→                    kind: DependencyKind::FunctionCall,
472→                    symbol: s.to_string(),
473→                    source_module: String::new(),
474→                    return_type: TypeInfo::Unknown,
475→                    param_types: vec![],
476→                    call_sites: vec![],
477→                })
478→                .collect(),
479→            return_type: TypeInfo::Unknown,
480→            start_line,
481→            end_line,
482→            literals: vec![],
483→            crypto_boundaries: vec![],
484→        }
485→    }
