464→        }
465→        out.push('\n');
466→    }
467→
468→    out.push_str("---\n\n");
469→
470→    // Classes
471→    for (i, class) in spec.classes.iter().enumerate() {
472→        out.push_str(&format!("## {}\n\n", class.label));
473→
474→        let pre_badge = provenance_badge(class.precondition_provenance);
